INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'os', 5, 1, NULL, 'E. M. Bounds em Os 5:1', 'E. M. Bounds interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Oseias 5, Deus revela arrependimento, justiça e restauração de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'E. M. Bounds', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'os', 6, 1, NULL, 'Atanásio em Os 6:1', 'Segundo Atanásio, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. Oseias 6 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'os', 7, 1, NULL, 'Thomas Watson em Os 7:1', 'Na leitura de Thomas Watson, vemos a piedade prática e a santificação do coração. Oseias 7 evidencia arrependimento, justiça e restauração como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'os', 8, 1, NULL, 'Andrew Murray em Os 8:1', 'Segundo Andrew Murray, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Oseias 8 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'os', 9, 1, NULL, 'Orígenes em Os 9:1', 'Orígenes destaca a leitura cristológica e eclesial da passagem. Em Oseias 9, o foco recai sobre arrependimento, justiça e restauração e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'os', 10, 1, NULL, 'Richard Baxter em Os 10:1', 'Richard Baxter interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Oseias 10, Deus revela arrependimento, justiça e restauração de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
